// 获取文档中所有表格信息，返回表格数量和位置
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var tableInfo = [];
for (var i = 1; i <= tables.Count; i++) {
    var table = tables.Item(i);
    var range = table.Range;
    var startPara = range.Paragraphs.Item(1).Range.ParagraphFormat;
    tableInfo.push({
        index: i,
        rowCount: table.Rows.Count,
        colCount: table.Columns.Count,
        start: range.Start,
        end: range.End
    });
}
return JSON.stringify({tableCount: tables.Count, tables: tableInfo.slice(0, 20)});

// 对文档中所有表格进行排版：表名黑体小五号居中，表格与页面等宽，跨页重复表头，表头黑体五号居中加粗，表格内容宋体五号靠左对齐
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var pageWidth = doc.PageSetup.PageWidth - doc.PageSetup.LeftMargin - doc.PageSetup.RightMargin;

for (var i = 1; i <= tables.Count; i++) {
    var table = tables.Item(i);

    // 设置表格宽度与页面等宽
    table.PreferredWidthType = 1; // wdPreferredWidthPercent
    table.PreferredWidth = 100;

    // 设置跨页重复表头
    if (table.Rows.Count > 1) {
        table.Rows.Item(1).HeadingFormat = true;
    }

    // 处理表头（第一行）：黑体五号居中加粗
    var headerRow = table.Rows.Item(1);
    for (var j = 1; j <= headerRow.Cells.Count; j++) {
        var cell = headerRow.Cells.Item(j);
        var range = cell.Range;
        range.Font.Name = "黑体";
        range.Font.Size = 10.5; // 五号
        range.Font.Bold = true;
        range.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter
    }

    // 处理表格内容（除表头外的行）：宋体五号靠左对齐
    for (var r = 2; r <= table.Rows.Count; r++) {
        var row = table.Rows.Item(r);
        for (var j = 1; j <= row.Cells.Count; j++) {
            var cell = row.Cells.Item(j);
            var range = cell.Range;
            range.Font.Name = "宋体";
            range.Font.Size = 10.5; // 五号
            range.ParagraphFormat.Alignment = 0; // wdAlignParagraphLeft
        }
    }

    // 查找表名段落（表格上方的段落），设置为黑体小五号居中
    var tableStart = table.Range.Start;
    var paras = doc.Paragraphs;
    for (var p = paras.Count; p >= 1; p--) {
        var para = paras.Item(p);
        var paraEnd = para.Range.End;
        if (paraEnd <= tableStart && tableStart - paraEnd < 500) {
            // 找到表格上方的段落
            var paraRange = para.Range;
            var paraText = paraRange.Text.replace(/\r/g, "").replace(/\n/g, "").replace(/\u0007/g, "");
            if (paraText.length > 0 && paraText.length < 100) {
                // 可能是表名
                paraRange.Font.Name = "黑体";
                paraRange.Font.Size = 9; // 小五号
                paraRange.ParagraphFormat.Alignment = 1; // 居中
                break;
            }
        }
    }
}

return "完成表格排版，共处理 " + tables.Count + " 个表格";

